#define MAX_N 100
int adj[MAX_N][MAX_N];
int deg[MAX_N];
int visited[MAX_N];

void add_edge(int u, int v) {
    adj[u][deg[u]++] = v;
    adj[v][deg[v]++] = u;
}

void dfs(int node) {
    visited[node] = 1;
    for (int i = 0; i < deg[node]; i++) {
        int nb = adj[node][i];
        if (!visited[nb]) dfs(nb);
    }
}

int main() {
    memset(deg, 0, sizeof(deg));
    memset(visited, 0, sizeof(visited));
    add_edge(0, 1);
    add_edge(1, 2);
    add_edge(3, 4);

    int components = 0;
    for (int i = 0; i < 6; i++) {
        if (!visited[i]) {
            dfs(i);
            components++;
        }
    }
    printf("%d\n", components);
    return 0;
}
